import{_ as a,o,c as t,ai as s}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"VPS Hosting","description":"","frontmatter":{"summary":"VPS hosting hub for OpenSoul (Oracle/Fly/Hetzner/GCP/exe.dev)","read_when":["You want to run the Gateway in the cloud","You need a quick map of VPS/hosting guides"],"title":"VPS Hosting"},"headers":[],"relativePath":"vps.md","filePath":"vps.md","lastUpdated":1771906665000}'),r={name:"vps.md"};function n(i,e,l,c,d,h){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="vps-hosting" tabindex="-1"><a class="header-anchor" href="#vps-hosting">#</a> VPS hosting</h1><p>This hub links to the supported VPS/hosting guides and explains how cloud deployments work at a high level.</p><h2 id="pick-a-provider" tabindex="-1"><a class="header-anchor" href="#pick-a-provider">#</a> Pick a provider</h2><ul><li><strong>Railway</strong> (one‑click + browser setup): <a href="/docs/install/railway">Railway</a></li><li><strong>Northflank</strong> (one‑click + browser setup): <a href="/docs/install/northflank">Northflank</a></li><li><strong>Oracle Cloud (Always Free)</strong>: <a href="/docs/platforms/oracle">Oracle</a> — $0/month (Always Free, ARM; capacity/signup can be finicky)</li><li><strong>Fly.io</strong>: <a href="/docs/install/fly">Fly.io</a></li><li><strong>Hetzner (Docker)</strong>: <a href="/docs/install/hetzner">Hetzner</a></li><li><strong>GCP (Compute Engine)</strong>: <a href="/docs/install/gcp">GCP</a></li><li><strong>exe.dev</strong> (VM + HTTPS proxy): <a href="/docs/install/exe-dev">exe.dev</a></li><li><strong>AWS (EC2/Lightsail/free tier)</strong>: works well too. Video guide: <a href="https://x.com/techfrenAJ/status/2014934471095812547" target="_blank" rel="noreferrer">https://x.com/techfrenAJ/status/2014934471095812547</a></li></ul><h2 id="how-cloud-setups-work" tabindex="-1"><a class="header-anchor" href="#how-cloud-setups-work">#</a> How cloud setups work</h2><ul><li>The <strong>Gateway runs on the VPS</strong> and owns state + workspace.</li><li>You connect from your laptop/phone via the <strong>Control UI</strong> or <strong>Tailscale/SSH</strong>.</li><li>Treat the VPS as the source of truth and <strong>back up</strong> the state + workspace.</li><li>Secure default: keep the Gateway on loopback and access it via SSH tunnel or Tailscale Serve. If you bind to <code>lan</code>/<code>tailnet</code>, require <code>gateway.auth.token</code> or <code>gateway.auth.password</code>.</li></ul><p>Remote access: <a href="/docs/gateway/remote">Gateway remote</a><br> Platforms hub: <a href="/docs/platforms/index">Platforms</a></p><h2 id="using-nodes-with-a-vps" tabindex="-1"><a class="header-anchor" href="#using-nodes-with-a-vps">#</a> Using nodes with a VPS</h2><p>You can keep the Gateway in the cloud and pair <strong>nodes</strong> on your local devices (Mac/iOS/Android/headless). Nodes provide local screen/camera/canvas and <code>system.run</code> capabilities while the Gateway stays in the cloud.</p><p>Docs: <a href="/docs/nodes/index">Nodes</a>, <a href="/docs/cli/nodes">Nodes CLI</a></p>',10)])])}const g=a(r,[["render",n]]);export{u as __pageData,g as default};
